#include <iostream>
#include <string>

int main() {
    // The game loop - the heart of every game
    bool isRunning = true;
    int playerHealth = 100;

    std::cout << "=== Welcome to the Arena ===" << std::endl;
    std::cout << "You are in a battle! Fight until you die or run." << std::endl;

    int round = 1;

    // The main game loop
    while (isRunning) {
        std::cout << "\n--- Round " << round << " ---" << std::endl;
        std::cout << "Health: " << playerHealth << std::endl;

        // Enemy attack
        int damage = rand() % 20 + 5;  // Random damage: 5-24
        playerHealth -= damage;

        std::cout << "Enemy hits you for " << damage << " damage!" << std::endl;

        // Check if dead
        if (playerHealth <= 0) {
            std::cout << "You have been defeated!" << std::endl;
            isRunning = false;  // Exit loop
        }

        round++;

        // Optional: ask to continue
        if (isRunning) {
            std::cout << "Press Enter to continue...";
            std::cin.ignore();
            std::cin.get();
        }
    }

    std::cout << "\n=== Game Over ===" << std::endl;
    std::cout << "You survived " << round << " rounds." << std::endl;

    // While loop counting
    std::cout << "\n=== Counting enemies ===" << std::endl;
    int enemyCount = 0;
    while (enemyCount < 5) {
        std::cout << "Spawned enemy #" << enemyCount + 1 << std::endl;
        enemyCount++;
    }

    return 0;
}

