#include <iostream>
#include <cstdlib>

int main() {
    int health = 100;

    std::cout << "=== Survival Mode ===" << std::endl;

    while (health > 0) {
        int damage = rand() % 21 + 5;  // 5-25 damage
        health -= damage;

        std::cout << "You took " << damage << " damage! Health: " << health << std::endl;
    }

    std::cout << "Game Over!" << std::endl;

    return 0;
}
